import{_ as t,o as a,c as i,an as o}from"./chunks/framework.D5fFzH9V.js";const y=JSON.parse('{"title":"Privacy Policy","description":"Privacy policy for handbook.syslifters.com.","frontmatter":{"description":"Privacy policy for handbook.syslifters.com.","search":false},"headers":[],"relativePath":"privacy.md","filePath":"privacy.md"}'),r={name:"privacy.md"};function s(n,e,c,h,l,p){return a(),i("div",null,[...e[0]||(e[0]=[o('<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /privacy.md for this page in Markdown format</div><h1 id="privacy-policy" tabindex="-1">Privacy Policy <a class="header-anchor" href="#privacy-policy" aria-label="Permalink to &quot;Privacy Policy&quot;">​</a></h1><p>The protection of your personal data is very important to us at Syslifters. We therefore process your data exclusively on the basis of the statutory provisions (GDPR, Austrian TKG 2003). In this data protection information we inform you about the most important aspects of data processing on our website.</p><p>This Data Privacy Policy applies to handbook.syslifters.com and is effective as of June 1, 2022.</p><p>‍</p><h2 id="hosting" tabindex="-1">Hosting <a class="header-anchor" href="#hosting" aria-label="Permalink to &quot;Hosting&quot;">​</a></h2><p>We host the website on GitHub. The provider is GitHub B.V., Prins Bernhardplein 200, Amsterdam, 1097JB, The Netherlands (hereinafter: GitHub). When you visit the website, GitHub collects various log files including your IP addresses.</p><p>For details, please refer to the <a href="https://docs.github.com/en/site-policy/privacy-policies/github-privacy-statement" target="_blank" rel="noreferrer">GitHub Privacy Policy</a>.</p><p>The use of GitHub is based on Art. 6 para. 1 lit. f DSGVO. We have a legitimate interest in ensuring that our website is presented as reliably as possible. Insofar as a corresponding consent has been requested, the processing is carried out exclusively on the basis of Art. 6 para. 1 lit. a DSGVO, insofar as the consent includes the storage of cookies or access to information in the user&#39;s terminal device (e.g. device fingerprinting). The consent can be revoked at any time.</p><h2 id="your-rights" tabindex="-1">Your rights <a class="header-anchor" href="#your-rights" aria-label="Permalink to &quot;Your rights&quot;">​</a></h2><p>In principle, you have the rights to information, correction, deletion, restriction, data portability, revocation and objection. If you believe that the processing of your data violates data protection law or your data protection rights have been violated in any other way, you have the right to file a complaint with the supervisory authority. In Austria, this is the data protection authority, E-Mail: <a href="mailto:dsb@dsb.gv.at" target="_blank" rel="noreferrer">dsb@dsb.gv.at</a>, Web: <a href="https://www.dsb.gv.at/" target="_blank" rel="noreferrer">https://www.dsb.gv.at/</a>.</p><h2 id="changes-to-this-privacy-policy" tabindex="-1">Changes to this privacy policy <a class="header-anchor" href="#changes-to-this-privacy-policy" aria-label="Permalink to &quot;Changes to this privacy policy&quot;">​</a></h2><p>We reserve the right to change our privacy policy if necessary, for example due to technical developments or legal changes. The latest version of the privacy policy is published on our website. Please make sure that you have the latest version.</p><p>You can reach us as follows:</p><p>Syslifters GmbH<br> Eitzersthal 75, 2013 Göllersdorf<br> E-Mail: <a href="mailto:hello@syslifters.com">hello@syslifters.com</a><br> Phone: +43 660 923 40 60</p><p>‍<strong>As of:</strong> 01. June 2022</p>',16)])])}const u=t(r,[["render",s]]);export{y as __pageData,u as default};
